/**
 * Performs a read-only fetch (no push) against the remote and reports whether it has diverged from the local history, so the UI can warn before a force-push discards those commits.
 * @summary Check whether the remote GitHub branch has commits not present locally
 */
export const GetGithubSyncDivergenceResponse = zod.object({
  "checked": zod.boolean().describe('Whether the divergence check could actually be performed (false if GITHUB_TOKEN is missing or the fetch failed)'),
  "diverged": zod.boolean().describe('True if the remote main branch has commits that are not present in the local history. A force-push would discard them.'),
  "remoteAheadBy": zod.number().optional().describe('Number of commits present on the remote but not reachable from local HEAD'),
  "repo": zod.string().optional().describe('GitHub repository that was checked'),
  "reason": zod.string().optional().describe('Human-readable reason the check could not be performed, or a note (e.g. remote branch does not exist yet)')
})


/**
 * @summary Get GitHub sync run history (last N runs)
 */
export const GetGithubSyncHistoryResponse = zod.object({
  "entries": zod.array(zod.object({
  "id": zod.string().optional().describe('Unique identifier for this sync run, used to fetch its full captured log via \/github-sync\/history\/{id}\/log. Absent on entries recorded before this field was introduced.'),
  "status": zod.enum(['success', 'failure', 'skipped']).describe('Outcome of the sync run — \"skipped\" means a divergence was detected and divergeAction was alert_only, so the push was intentionally skipped to protect remote history'),
  "syncedAt": zod.coerce.date().describe('ISO timestamp of when the sync completed'),
  "repo": zod.string().describe('GitHub repository that was synced'),
  "errorMessage": zod.string().optional().describe('Error detail when status is \"failure\"'),
  "hasLog": zod.boolean().optional().describe('Whether a full captured log is available for this run via \/github-sync\/history\/{id}\/log'),
  "retryOf": zod.string().optional().describe('ID of the earlier failed sync run that this run was retrying, if this run was triggered as a retry.'),
  "skipReason": zod.string().optional().describe('Human-readable explanation of why the run was skipped, e.g. \"Remote was ahead by 3 commit(s) at the time of the skip\". Only present when status is \"skipped\".'),
  "remoteAheadBy": zod.number().optional().describe('Number of commits the remote was ahead of local HEAD at the time the sync was skipped due to divergence. Only present when status is \"skipped\".')
})).describe('Past sync runs, newest first, capped at 50')
})


